export class NovaPoshtaService {
  private apiKey: string;
  private apiUrl = "https://api.novaposhta.ua/v2.0/json/";

  constructor() {
    this.apiKey = process.env.NOVA_POSHTA_API_KEY || "";
  }

  async getCities(cityName: string = "") {
    if (!this.apiKey) {
      console.warn("Nova Poshta API key is missing; returning empty cities list.");
      return [];
    }

    try {
      const response = await fetch(this.apiUrl, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          apiKey: this.apiKey,
          modelName: "Address",
          calledMethod: "getCities",
          methodProperties: { FindByString: cityName }
        })
      });
      const data = await response.json();
      return data.success ? data.data : [];
    } catch (e) {
      console.error("NP API Error:", e);
      return [];
    }
  }

  async createInternetDocument(
    buyerInfo: Record<string, unknown>,
    sellerInfo: Record<string, unknown>,
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    weight: number = 1,
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    cost: number
  ) {
    console.warn("Nova Poshta document creation is not enabled. No TTN generated.");
    return {
      success: false,
      ttn: null,
      estimatedDeliveryDate: null
    };
  }
}

export const npService = new NovaPoshtaService();
